```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2];
    pipe(fd);

    pid_t pid = fork();

    if (pid == -1) {
        std::cerr << "Erreur lors de la création du processus fils" << std::endl;
        return 1;
    }

    if (pid == 0) { // C'est le processus fils
        close(fd[1]); // Fermer l'écriture
        dup2(fd[0], STDIN_FILENO); // Rediriger l'entrée
        close(fd[0]); // Fermer le file descriptor non nécessaire

        execlp("commande", "commande", NULL); // Remplacez "commande" par la commande que vous voulez exécuter

        std::cerr << "Erreur lors de l'exécution de la commande" << std::endl;
        _exit(1);
    } else { // C'est le processus père
        close(fd[0]); // Fermer la lecture
        dup2(fd[1], STDOUT_FILENO); // Rediriger la sortie
        close(fd[1]); // Fermer le file descriptor non nécessaire

        std::cout << "Salut de la part du processus père!" << std::endl;

        int status;
        waitpid(pid, &status, 0);
    }

    return 0;
}
```

N'oubliez pas de remplacer `"commande"` par la commande que vous souhaitez exécuter dans le processus fils. Amusez-vous bien avec votre code en français!
